  1	import React, { Dispatch, FC, SetStateAction, useState } from 'react';
  2	
  3	import { IoK8sApiCoreV1Secret } from '@kubevirt-ui/kubevirt-api/kubernetes';
  4	import FormGroupHelperText from '@kubevirt-utils/components/FormGroupHelperText/FormGroupHelperText';
  5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  6	import { getValidNamespace, validateSSHPublicKey } from '@kubevirt-utils/utils/utils';
  7	import { useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
  8	import {
  9	  FileUpload,
 10	  Form,
 11	  FormGroup,
 12	  HelperText,
 13	  HelperTextItem,
 14	  TextInput,
 15	  ValidatedOptions,
 16	} from '@patternfly/react-core';
 17	
 18	import { SecretSelectionOption, SSHSecretDetails } from '../../utils/types';
 19	import { getSecretNameErrorMessage } from '../../utils/utils';
 20	
 21	import './SSHKeyUpload.scss';
 22	
 23	type SSHKeyUploadProps = {
 24	  secrets: IoK8sApiCoreV1Secret[];
 25	  setSSHDetails: Dispatch<SetStateAction<SSHSecretDetails>>;
 26	  sshDetails: SSHSecretDetails;
 27	};
 28	
 29	const SSHKeyUpload: FC<SSHKeyUploadProps> = ({ secrets, setSSHDetails, sshDetails }) => {
 30	  const { t } = useKubevirtTranslation();
 31	  const [activeNamespace] = useActiveNamespace();
 32	  const [nameErrorMessage, setNameErrorMessage] = useState<string>(null);
 33	  const [isValidKey, setIsValidKey] = useState<boolean>(true);
 34	  const [isLoading, setIsLoading] = useState<boolean>(false);
 35	
 36	  const vmNamespaceTarget = getValidNamespace(activeNamespace);
 37	
 38	  const validated = !nameErrorMessage ? ValidatedOptions.default : ValidatedOptions.error;
 39	
 40	  const onChange = (_, sshPublicKey: string) => {
 41	    setIsValidKey(validateSSHPublicKey(sshPublicKey));
 42	    setSSHDetails({
 43	      ...sshDetails,
 44	      secretOption: SecretSelectionOption.addNew,
 45	      sshPubKey: sshPublicKey?.trim(),
 46	    });
 47	  };
 48	
 49	  return (
 50	    <Form isHorizontal>
 51	      <FileUpload
 52	        onClearClick={() => {
 53	          setSSHDetails({
 54	            ...sshDetails,
 55	            secretOption: SecretSelectionOption.addNew,
 56	            sshPubKey: '',
 57	          });
 58	        }}
 59	        onFileInputChange={async (_, file: File) => {
 60	          const fileText = await file.text();
 61	          setIsValidKey(validateSSHPublicKey(fileText));
 62	          setSSHDetails({
 63	            ...sshDetails,
 64	            secretOption: SecretSelectionOption.addNew,
 65	            sshPubKey: fileText?.trim(),
 66	          });
 67	        }}
 68	        allowEditingUploadedText
 69	        browseButtonText={t('Upload')}
 70	        className="ssh-key-upload__file-upload"
 71	        id="ssh-key-upload"
 72	        isLoading={isLoading}
 73	        isReadOnly={false}
 74	        onDataChange={onChange}
 75	        onReadFinished={() => setIsLoading(false)}
 76	        onReadStarted={() => setIsLoading(true)}
 77	        onTextChange={onChange}
 78	        type="text"
 79	        validated={isValidKey ? ValidatedOptions.default : ValidatedOptions.error}
 80	        value={sshDetails?.sshPubKey}
 81	      >
 82	        {!isValidKey && (
 83	          <HelperText>
 84	            <HelperTextItem variant="error">{t('SSH key is invalid')}</HelperTextItem>
 85	          </HelperText>
 86	        )}
 87	      </FileUpload>
 88	      <FormGroup
 89	        className="ssh-key-upload__form-group"
 90	        fieldId="new-secret-name"
 91	        isInline
 92	        isRequired
 93	        label={t('Secret name')}
 94	      >
 95	        <TextInput
 96	          onChange={(_event, secretName: string) => {
 97	            setNameErrorMessage(getSecretNameErrorMessage(secretName, vmNamespaceTarget, secrets));
 98	            setSSHDetails({
 99	              ...sshDetails,
100	              secretOption: SecretSelectionOption.addNew,
101	              // secret name must be under 51 chars, or machine will fail starting.
102	              sshSecretName: secretName.substring(0, 51),
103	            });
104	          }}
105	          id="new-secret-name"
106	          isRequired
107	          name="new-secret-name"
108	          type="text"
109	          value={sshDetails?.sshSecretName}
110	        />
111	        <FormGroupHelperText validated={validated}>
112	          {nameErrorMessage && nameErrorMessage}
113	        </FormGroupHelperText>
114	      </FormGroup>
115	    </Form>
116	  );
117	};
118	
119	export default SSHKeyUpload;

